import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface ErrorRateTrend {
  time: string;
  rate: number;
}

interface ApiUsageData {
  requestCount: number;
  averageLatency: number;
  errorRate: number;
  errorRateTrend: ErrorRateTrend[];
}

export default function Widget() {
  const apiUsageData = response.data as ApiUsageData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107' }}>
              API Monitor
            </Typography>
            <Stack direction="row" spacing={0.5}>
              <Chip label={`Requests: ${apiUsageData.requestCount}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#673AB7', color: '#FFFFFF' }} />
              <Chip label={`Latency: ${apiUsageData.averageLatency}ms`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#673AB7', color: '#FFFFFF' }} />
              <Chip label={`Error Rate: ${apiUsageData.errorRate}%`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#673AB7', color: '#FFFFFF' }} />
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              height={140}
              series={[
                {
                  data: apiUsageData.errorRateTrend.map(d => d.rate),
                  color: '#FFC107',
                },
              ]}
              xAxis={[
                {
                  data: apiUsageData.errorRateTrend.map(d => d.time),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#FFFFFF',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
